def execute_tool_call(tool_name, arguments):
    # 1. The Guardrail: Never trust the LLM's choice implicitly
    if tool_name == "drop_database":
        raise ValueError("CRITICAL: Model attempted prohibited action.")

    # 2. Argument validation
    if tool_name == "send_email":
        if "@ourcompany.com" not in arguments.get("to_address", ""):
            # Return a soft error so the model can fix it
            return "Error: You are only allowed to email internal addresses."

    # 3. Execution (if safe)
    return run_actual_function(tool_name, arguments)

import pydantic

class UserProfile(pydantic.BaseModel):
    age: int
    email: str

def get_profile_with_retries(user_text, max_retries=3):
    messages = [{'role': 'user', 'content': user_text}]

    for _ in range(max_retries):
        response = llm.generate(messages, response_format='json')
        try:
            # The Guardrail: Pydantic enforces strict types
            valid_profile = UserProfile.model_validate_json(response)
            return valid_profile

        except pydantic.ValidationError as e:
            # Self-correction loop
            messages.append({'role': 'assistant', 'content': response})
            messages.append({'role': 'user', 'content': f"JSON Error: {e}. Fix it."})
